// ── Types ────────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  headers: string[];
  rows: Record<string, unknown>[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// ── Defaults ─────────────────────────────────────────────────────────────────

const DEFAULTS: Required<CSVOptions> = {
  delimiter: ",",
  quote: '"',
  lineSeparator: "\n",
};

// ── Field-level parsing (handles quotes + escapes) ───────────────────────────

function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // trailing delimiter produced an empty final field
      fields.push("");
      break;
    }

    if (line[i] === quote) {
      // ── quoted field ──
      let value = "";
      i++; // skip opening quote
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            // escaped quote
            value += quote;
            i += 2;
          } else {
            // closing quote
            i++; // skip closing quote
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      // skip delimiter (or we're at end)
      if (i < len && line[i] === delimiter) {
        i++;
        // if delimiter is the very last char, there's one more empty field
        if (i === len) {
          fields.push("");
          break;
        }
      } else {
        // either end-of-line or unexpected char after closing quote – skip to
        // next delimiter so we don't get stuck
        while (i < len && line[i] !== delimiter) i++;
        if (i < len) {
          i++; // skip delimiter
          if (i === len) {
            fields.push("");
            break;
          }
        } else {
          break;
        }
      }
    } else {
      // ── unquoted field ──
      let end = i;
      while (end < len && line[end] !== delimiter) end++;
      fields.push(line.substring(i, end));
      i = end + 1; // skip past delimiter
      if (end === len) break; // no delimiter found – we're done
      if (i === len) {
        // trailing delimiter
        fields.push("");
        break;
      }
    }
  }

  return fields;
}

// ── Type coercion ────────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // null / empty
  if (value === "" || value === "null" || value === "NULL") return null;

  // boolean (case-insensitive)
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // number – only if the *entire* trimmed string is numeric
  if (/^-?\d+$/.test(value)) {
    const n = Number(value);
    if (Number.isSafeInteger(n)) return n;
  }
  if (/^-?\d+\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  return value;
}

// ── Split input into lines respecting quoted fields that contain newlines ────

function splitLines(
  input: string,
  lineSeparator: string,
  quote: string
): string[] {
  const lines: string[] = [];
  let current = "";
  let insideQuote = false;
  let i = 0;

  while (i < input.length) {
    // check for line separator (may be multi-char, e.g. \r\n)
    if (
      !insideQuote &&
      input.substring(i, i + lineSeparator.length) === lineSeparator
    ) {
      lines.push(current);
      current = "";
      i += lineSeparator.length;
      continue;
    }

    const ch = input[i];
    if (ch === quote) {
      insideQuote = !insideQuote;
    }
    current += ch;
    i++;
  }

  // push last segment
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ── Main entry point ─────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const opts: Required<CSVOptions> = { ...DEFAULTS, ...options };
  const { delimiter, quote, lineSeparator } = opts;

  const errors: CSVError[] = [];

  // Handle degenerate inputs
  const trimmed = input.trim();
  if (trimmed.length === 0) {
    return buildResult([], [], errors);
  }

  const lines = splitLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // First line → headers
  const headers = parseFields(lines[0], delimiter, quote).map((h) => h.trim());

  const rows: Record<string, unknown>[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    // skip completely blank lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1, // 1-based, header is row 1
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      continue; // skip malformed row
    }

    const record: Record<string, unknown> = {};
    for (let j = 0; j < headers.length; j++) {
      record[headers[j]] = coerce(fields[j]);
    }
    rows.push(record);
  }

  return buildResult(headers, rows, errors);
}

// ── Build the result object with helper methods ──────────────────────────────

function buildResult(
  headers: string[],
  rows: Record<string, unknown>[],
  errors: CSVError[]
): CSVResult {
  return {
    headers,
    rows,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean) {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

import { parseCSV } from "./csv-parser";

// ── tiny assertion helpers ───────────────────────────────────────────────────

let passed = 0;
let failed = 0;
let currentSuite = "";

function suite(name: string) {
  currentSuite = name;
  console.log(`\n━━ ${name} ━━`);
}

function assert(condition: boolean, message: string) {
  if (!condition) {
    failed++;
    console.error(`  ✗ [${currentSuite}] ${message}`);
    throw new Error(`Assertion failed: [${currentSuite}] ${message}`);
  }
  passed++;
  console.log(`  ✓ ${message}`);
}

function eq(actual: unknown, expected: unknown, label: string) {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  assert(a === e, `${label}  (got ${a}, expected ${e})`);
}

function approx(actual: number, expected: number, label: string, eps = 1e-9) {
  assert(
    Math.abs(actual - expected) < eps,
    `${label}  (got ${actual}, expected ${expected})`
  );
}

// ═════════════════════════════════════════════════════════════════════════════
// Tests
// ═════════════════════════════════════════════════════════════════════════════

// ── Basic parsing ────────────────────────────────────────────────────────────

suite("Basic parsing");
{
  const csv = `name,age,city
Alice,30,New York
Bob,25,London`;

  const result = parseCSV(csv);
  eq(result.headers, ["name", "age", "city"], "headers parsed");
  eq(result.rows.length, 2, "two data rows");
  eq(result.rows[0]["name"], "Alice", "first row name");
  eq(result.rows[0]["age"], 30, "first row age is number");
  eq(result.rows[0]["city"], "New York", "first row city");
  eq(result.rows[1]["name"], "Bob", "second row name");
  eq(result.rows[1]["age"], 25, "second row age is number");
  eq(result.errors.length, 0, "no errors");
}

// ── Quoted fields with commas ────────────────────────────────────────────────

suite("Quoted fields with commas");
{
  const csv = `name,address,city
Alice,"123 Main St, Apt 4",Springfield
Bob,"456 Oak Ave, Suite 100",Shelbyville`;

  const result = parseCSV(csv);
  eq(result.rows[0]["address"], "123 Main St, Apt 4", "comma inside quotes preserved");
  eq(result.rows[1]["address"], "456 Oak Ave, Suite 100", "second quoted field");
  eq(result.errors.length, 0, "no errors");
}

// ── Escaped quotes ───────────────────────────────────────────────────────────

suite("Escaped quotes");
{
  const csv = `name,quote
Alice,"She said ""hello""."
Bob,"He replied ""goodbye""."`;

  const result = parseCSV(csv);
  eq(result.rows[0]["quote"], 'She said "hello".', "escaped quotes become literal");
  eq(result.rows[1]["quote"], 'He replied "goodbye".', "second row escaped quotes");
}

// ── Custom delimiters ────────────────────────────────────────────────────────

suite("Custom delimiters");
{
  // tab-separated
  const tsv = `name\tage\tcity
Alice\t30\tNew York
Bob\t25\tLondon`;

  const result = parseCSV(tsv, { delimiter: "\t" });
  eq(result.headers, ["name", "age", "city"], "tab headers");
  eq(result.rows[0]["name"], "Alice", "tab field");
  eq(result.rows[0]["age"], 30, "tab number field");
}

{
  // semicolon delimiter + single-quote as quote char
  const csv = `name;desc
Alice;'has;semicolons'`;

  const result = parseCSV(csv, { delimiter: ";", quote: "'" });
  eq(result.rows[0]["desc"], "has;semicolons", "semicolon inside single quotes");
}

{
  // custom line separator \r\n
  const csv = "name,age\r\nAlice,30\r\nBob,25";
  const result = parseCSV(csv, { lineSeparator: "\r\n" });
  eq(result.rows.length, 2, "CRLF line separator");
  eq(result.rows[0]["name"], "Alice", "CRLF first row");
}

// ── Type coercion ────────────────────────────────────────────────────────────

suite("Type coercion – integers");
{
  const csv = `val
0
42
-7
999999`;
  const result = parseCSV(csv);
  eq(result.rows[0]["val"], 0, "zero");
  eq(result.rows[1]["val"], 42, "positive int");
  eq(result.rows[2]["val"], -7, "negative int");
  eq(result.rows[3]["val"], 999999, "large int");
}

suite("Type coercion – floats");
{
  const csv = `val
3.14
-0.5
100.00`;
  const result = parseCSV(csv);
  approx(result.rows[0]["val"] as number, 3.14, "pi-ish");
  approx(result.rows[1]["val"] as number, -0.5, "negative float");
  approx(result.rows[2]["val"] as number, 100.0, "trailing zeros float");
}

suite("Type coercion – booleans");
{
  const csv = `val
true
TRUE
True
false
FALSE
False`;
  const result = parseCSV(csv);
  eq(result.rows[0]["val"], true, "true lowercase");
  eq(result.rows[1]["val"], true, "TRUE uppercase");
  eq(result.rows[2]["val"], true, "True mixed");
  eq(result.rows[3]["val"], false, "false lowercase");
  eq(result.rows[4]["val"], false, "FALSE uppercase");
  eq(result.rows[5]["val"], false, "False mixed");
}

suite("Type coercion – nulls");
{
  const csv = `a,b,c
null,NULL,`;
  const result = parseCSV(csv);
  eq(result.rows[0]["a"], null, "null string → null");
  eq(result.rows[0]["b"], null, "NULL string → null");
  eq(result.rows[0]["c"], null, "empty string → null");
}

suite("Type coercion – strings stay strings");
{
  const csv = `val
hello
123abc
true_ish
12.34.56`;
  const result = parseCSV(csv);
  eq(result.rows[0]["val"], "hello", "plain string");
  eq(result.rows[1]["val"], "123abc", "alphanumeric stays string");
  eq(result.rows[2]["val"], "true_ish", "partial bool stays string");
  eq(result.rows[3]["val"], "12.34.56", "multi-dot stays string");
}

// ── Malformed rows & error collection ────────────────────────────────────────

suite("Malformed row error collection");
{
  const csv = `name,age,city
Alice,30,New York
Bob,25
Charlie,35,Boston,extra`;
  const result = parseCSV(csv);
  eq(result.rows.length, 1, "only valid row kept");
  eq(result.rows[0]["name"], "Alice", "valid row is Alice");
  eq(result.errors.length, 2, "two errors collected");
  eq(result.errors[0].row, 3, "error on row 3 (Bob)");
  assert(result.errors[0].message.includes("2"), "Bob error mentions field count 2");
  eq(result.errors[1].row, 4, "error on row 4 (Charlie)");
  assert(result.errors[1].message.includes("4"), "Charlie error mentions field count 4");
}

// ── Filter ───────────────────────────────────────────────────────────────────

suite("Filter");
{
  const csv = `name,age,active
Alice,30,true
Bob,25,false
Charlie,35,true
Diana,28,false`;

  const result = parseCSV(csv);

  const active = result.filter((r) => r["active"] === true);
  eq(active.length, 2, "2 active rows");
  eq(active[0]["name"], "Alice", "first active is Alice");
  eq(active[1]["name"], "Charlie", "second active is Charlie");

  const over28 = result.filter((r) => (r["age"] as number) > 28);
  eq(over28.length, 2, "2 rows age > 28");
  eq(over28[0]["name"], "Alice", "Alice > 28");
  eq(over28[1]["name"], "Charlie", "Charlie > 28");

  const noMatch = result.filter((r) => (r["age"] as number) > 100);
  eq(noMatch.length, 0, "no matches returns empty");
}

// ── Aggregation: sum ─────────────────────────────────────────────────────────

suite("Aggregation – sum");
{
  const csv = `item,qty,price
A,10,1.5
B,20,2.5
C,30,3.5`;
  const result = parseCSV(csv);
  eq(result.sum("qty"), 60, "sum of qty");
  approx(result.sum("price"), 7.5, "sum of price");
  eq(result.sum("item"), 0, "sum of non-numeric column is 0");
}

// ── Aggregation: average ─────────────────────────────────────────────────────

suite("Aggregation – average");
{
  const csv = `name,score
A,10
B,20
C,30`;
  const result = parseCSV(csv);
  approx(result.average("score"), 20, "average of score");
  eq(result.average("name"), 0, "average of non-numeric column is 0");
}

// ── Aggregation: count ───────────────────────────────────────────────────────

suite("Aggregation – count");
{
  const csv = `x
1
2
3
4
5`;
  const result = parseCSV(csv);
  eq(result.count(), 5, "count is 5");
}

// ── Aggregation: groupBy ─────────────────────────────────────────────────────

suite("Aggregation – groupBy");
{
  const csv = `name,dept,salary
Alice,eng,100
Bob,sales,80
Charlie,eng,120
Diana,sales,90
Eve,eng,110`;
  const result = parseCSV(csv);

  const groups = result.groupBy("dept");
  eq(groups.size, 2, "two groups");

  const eng = groups.get("eng")!;
  eq(eng.length, 3, "3 in eng");
  eq(eng[0]["name"], "Alice", "eng first");

  const sales = groups.get("sales")!;
  eq(sales.length, 2, "2 in sales");
  eq(sales[0]["name"], "Bob", "sales first");
}

// ── Edge case: empty input ───────────────────────────────────────────────────

suite("Edge case – empty input");
{
  const result = parseCSV("");
  eq(result.headers.length, 0, "no headers");
  eq(result.rows.length, 0, "no rows");
  eq(result.errors.length, 0, "no errors");
  eq(result.count(), 0, "count 0");
  eq(result.sum("x"), 0, "sum 0");
  eq(result.average("x"), 0, "average 0");
  eq(result.filter(() => true).length, 0, "filter empty");
  eq(result.groupBy("x").size, 0, "groupBy empty");
}

{
  const result = parseCSV("   \n  \n  ");
  eq(result.headers.length, 0, "whitespace-only → no headers");
  eq(result.rows.length, 0, "whitespace-only → no rows");
}

// ── Edge case: headers only, no data ─────────────────────────────────────────

suite("Edge case – headers only");
{
  const result = parseCSV("a,b,c");
  eq(result.headers, ["a", "b", "c"], "headers present");
  eq(result.rows.length, 0, "no data rows");
}

// ── Edge case: single column ─────────────────────────────────────────────────

suite("Edge case – single column");
{
  const csv = `value
42
hello
true`;
  const result = parseCSV(csv);
  eq(result.headers, ["value"], "single header");
  eq(result.rows.length, 3, "three rows");
  eq(result.rows[0]["value"], 42, "number coerced");
  eq(result.rows[1]["value"], "hello", "string kept");
  eq(result.rows[2]["value"], true, "boolean coerced");
}

// ── Edge case: single row ────────────────────────────────────────────────────

suite("Edge case – single row");
{
  const csv = `a,b,c
1,2,3`;
  const result = parseCSV(csv);
  eq(result.rows.length, 1, "one data row");
  eq(result.rows[0]["a"], 1, "a=1");
  eq(result.rows[0]["b"], 2, "b=2");
  eq(result.rows[0]["c"], 3, "c=3");
}

// ── Edge case: very large fields ─────────────────────────────────────────────

suite("Edge case – very large fields");
{
  const bigValue = "x".repeat(100_000);
  const csv = `data\n${bigValue}`;
  const result = parseCSV(csv);
  eq(result.rows.length, 1, "one row");
  eq((result.rows[0]["data"] as string).length, 100_000, "100k chars preserved");
}

{
  const bigQuoted = "y".repeat(50_000) + "," + "z".repeat(50_000);
  const csv = `data\n"${bigQuoted}"`;
  const result = parseCSV(csv);
  eq(
    (result.rows[0]["data"] as string).length,
    100_001,
    "large quoted field with comma preserved"
  );
}

// ── Quoted fields with newlines inside ───────────────────────────────────────

suite("Quoted fields with embedded newlines");
{
  const csv = `name,bio
Alice,"Line one
Line two"
Bob,"Single line"`;
  const result = parseCSV(csv);
  eq(result.rows.length, 2, "two rows");
  eq(result.rows[0]["bio"], "Line one\nLine two", "newline in quoted field");
  eq(result.rows[1]["bio"], "Single line", "normal field after multiline");
}

// ── Mixed quoting and escaping in same field ─────────────────────────────────

suite("Complex quoting");
{
  const csv = `val
"He said ""hi"", then left"
"comma,and""quote"`;
  const result = parseCSV(csv);
  eq(result.rows[0]["val"], 'He said "hi", then left', "mixed comma+escaped quotes");
  eq(result.rows[1]["val"], 'comma,and"quote', "comma and escaped quote together");
}

// ── groupBy with coerced types as keys ───────────────────────────────────────

suite("groupBy with null/boolean keys");
{
  const csv = `status,val
true,1
false,2
true,3
null,4`;
  const result = parseCSV(csv);
  const groups = result.groupBy("status");
  eq(groups.get(true)!.length, 2, "2 true rows");
  eq(groups.get(false)!.length, 1, "1 false row");
  eq(groups.get(null)!.length, 1, "1 null row");
}

// ── sum/average ignore nulls and non-numbers ─────────────────────────────────

suite("sum/average with mixed types");
{
  const csv = `label,val
a,10
b,null
c,20
d,hello
e,30`;
  const result = parseCSV(csv);
  eq(result.sum("val"), 60, "sum skips null and string");
  approx(result.average("val"), 20, "average over 3 numeric values");
}

// ═════════════════════════════════════════════════════════════════════════════
// Summary
// ═════════════════════════════════════════════════════════════════════════════

console.log("\n══════════════════════════════════════");
console.log(`  ${passed} passed, ${failed} failed`);
console.log("══════════════════════════════════════\n");

if (failed > 0) {
  process.exit(1);
}

